mapper.select:
SELECT COUNT(DISTINCT C.ID) as count
FROM
course c
LEFT JOIN course_arrangement ca ON ca.cid = c.ID
WHERE  1=1


		and c.state = #{state,jdbcType=INTEGER}


		and c.state in (2,3,4)




		and 1=1


		and c.creatorid = #{tid,jdbcType=VARCHAR}


		and 1=0



	and c.name_c like '%'||#{cname}||'%'


	and c.unitid = #{unitid,jdbcType=VARCHAR}


	and ca.aid = #{arrangeid,jdbcType=VARCHAR}


	and c.deptid = #{depid,jdbcType=VARCHAR}


	and to_date(#{begindate},'yyyy-MM-dd') <= trunc(c.creattime) and to_date(#{enddate},'yyyy-MM-dd') >= trunc(c.creattime)

select count(distinct c.id) as tar from
course c
left join course_arrangement ca on ca.cid = c.id
WHERE (
	EXISTS (
		SELECT 1
		FROM teacher_permission tp
		WHERE tp.cid = c.id
		AND tp.tid = #{tid,jdbcType=VARCHAR}
		AND (tp.pid = '15' or tp.pid = '10')
	)
	OR c.creatorid = #{tid,jdbcType=VARCHAR}
)

	and c.name_c like '%'||#{cname}||'%'



	and c.name_c like '%'||#{cname}||'%'


	and c.unitid = #{unitid,jdbcType=VARCHAR}


	and ca.aid = #{arrangeid,jdbcType=VARCHAR}


	and c.deptid = #{depid,jdbcType=VARCHAR}


	and to_date(#{begindate},'yyyy-MM-dd') <= trunc(c.creattime) and to_date(#{enddate},'yyyy-MM-dd') >= trunc(c.creattime)

select cq.qtid, cq.qtname, cq.iscon as iscon, cq.atid, cq.qtdesc,cq.xxdf
  from course_questiontype cq where cq.state=0 and cq.cid = #{id,jdbcType=VARCHAR}
 order by cq.qtorder

WITH ids AS (

		SELECT TO_NCHAR(REGEXP_SUBSTR(#{item,jdbcType=NVARCHAR}, '[^,]+', 1, LEVEL)) AS cid FROM dual
		CONNECT BY LEVEL <= LENGTH(#{item,jdbcType=NVARCHAR}) - LENGTH(REPLACE(#{item,jdbcType=NVARCHAR}, ',', '')) + 1

)
SELECT c.id AS cid
FROM course c
JOIN (SELECT DISTINCT cid FROM ids) i ON i.cid = c.id
WHERE c.state = 1

	AND c.name_c LIKE '%'||#{cname}||'%'


	AND c.unitid = #{unitid,jdbcType=VARCHAR}


	AND c.deptid = #{depid,jdbcType=VARCHAR}


	AND TRUNC(c.creattime) BETWEEN TO_DATE(#{begindate}, 'yyyy-MM-dd') AND TO_DATE(#{enddate}, 'yyyy-MM-dd')


	AND EXISTS (
		SELECT 1 FROM course_arrangement ca WHERE ca.cid = c.id AND ca.aid = #{arrangeid,jdbcType=VARCHAR}
	)


	AND EXISTS (
	SELECT 1 FROM question_db qd
		WHERE qd.cid = c.id AND TRUNC(qd.addtime) BETWEEN TO_DATE(#{bdate}, 'yyyy-MM-dd') AND TO_DATE(#{edate}, 'yyyy-MM-dd')
	)

WITH ids AS (

		SELECT TO_NCHAR(REGEXP_SUBSTR(#{item,jdbcType=NVARCHAR}, '[^,]+', 1, LEVEL)) AS cid FROM dual
		CONNECT BY LEVEL <= LENGTH(#{item,jdbcType=NVARCHAR}) - LENGTH(REPLACE(#{item,jdbcType=NVARCHAR}, ',', '')) + 1

)
SELECT COUNT(*) AS tar FROM course c JOIN (SELECT DISTINCT cid FROM ids) i ON i.cid = c.id
WHERE 1=1


		AND c.state = #{state}


		AND c.state = 1



	AND c.name_c LIKE '%'||#{cname}||'%'


	AND c.unitid = #{unitid,jdbcType=VARCHAR}


	AND c.deptid = #{depid,jdbcType=VARCHAR}


	AND EXISTS (
		SELECT 1 FROM course_arrangement ca WHERE ca.cid = c.id AND ca.aid = #{arrangeid,jdbcType=VARCHAR}
	)


	AND TRUNC(c.creattime) BETWEEN TO_DATE(#{begindate}, 'yyyy-MM-dd') AND TO_DATE(#{enddate}, 'yyyy-MM-dd')

select count(name_c) as tar from course where
name_c = #{val}

and id != #{thiscid}

and state=1

