select c.id, c.name_c, c.name_e, u.name as uname, nvl(cq.question_total,0) as questioncount from course_specialty cs, course c left join unit u on u.id = c.unitid left join course_ques_page_total cq ON cq.cid = c.id where c.open = 1 and c.state=1 and cs.cid = c.id and cs.spid = #{spid,jdbcType=VARCHAR}
and (c.name_c like '%'||#{cname}||'%' or c.name_e like '%'||#{cname}||'%')
and c.unitid = #{unitid}

select count(c.id) as num
from course_specialty cs, course c
where c.open = 1 and c.state=1 and cs.cid = c.id and cs.spid = #{spid,jdbcType=VARCHAR}

	and (c.name_c like '%'||#{cname}||'%' or c.name_e like '%'||#{cname}||'%')


	and c.unitid = #{unitid}

