mapper.select:
SELECT
CASE
WHEN EXISTS (
	SELECT 1
	FROM question_db q
	WHERE q.state != 2
	AND q.cid = #{cid,jdbcType=NVARCHAR}

		AND q.theme2id = #{thid}
		AND q.theme3id = #{thid}
		AND q.theme1id = #{thid}

)
OR EXISTS (
	SELECT 1
	FROM exampaper_question_db eq
	INNER JOIN exampaper_course ec
	ON ec.eid = eq.eid AND ec.cid = #{cid}

		AND eq.theme2id = #{thid}
		AND eq.theme3id = #{thid}
		AND eq.theme1id = #{thid}

)
THEN 1 ELSE 0 END
FROM dual
